module multi_booth_8bit (
    output reg [15:0] p,
    output reg rdy,
    input clk,
    input reset,
    input [7:0] a,
    input [7:0] b
);

	reg [15:0] multiplier, multiplicand;
	reg [4:0] ctr;

	always@(posedge clk, posedge (reset)) begin
		if(reset) begin
			multiplicand <= {{8{a[7]}}, a};
			multiplier <= {{8{b[7]}}, b};
			p <= 0;
			rdy <= 0;
			ctr <= 0;
		end

		else begin
			if(ctr < 16) begin
				multiplicand <= multiplicand << 1;
				if(multiplier[ctr])
					p <= p + multiplicand;
				ctr <= ctr + 1;
			end

				rdy <= 1;
		end
	end

endmodule
